    let mut seen: HashSet<i32> = HashSet::new();
    println!("{}", seen.insert(10));  // true (new)
    println!("{}", seen.insert(20));  // true
    println!("{}", seen.insert(10));  // false (duplicate)

    println!("{}", seen.contains(&10));  // true
    println!("{}", seen.contains(&30));  // false
    println!("{}", seen.len());          // 2
}

