fn has_duplicates(nums: &[i32]) -> bool {
    let mut seen = HashSet::new();
    for &num in nums {
        if !seen.insert(num) {
            return true;
        }
    }
    false
}

fn main() {
    println!("{}", has_duplicates(&[1, 2, 3, 4]));    // false
    println!("{}", has_duplicates(&[1, 2, 3, 1]));    // true
}

