fn first_duplicate(nums: &[i32]) -> Option<i32> {
    let mut seen = HashSet::new();
    for &num in nums {
        if !seen.insert(num) {
            return Some();
        }
    }
    None
}

fn main() {
    println!("{:?}", first_duplicate(&[5, 3, 4, 2, 3, 7]));
    println!("{:?}", first_duplicate(&[1, 2, 3]));
}

