fn main() {
    let a: HashSet<i32> = [1, 2, 3, 4].iter().cloned().collect();
    let b: HashSet<i32> = [3, 4, 5, 6].iter().cloned().collect();

    let inter: Vec<&i32> = a.intersection(&b).collect();
    println!("{:?}", inter);  // [3, 4] (order may vary)

    let uni: Vec<&i32> = a.union(&b).collect();
    println!("{}", uni.len());  // 6
}

