fn dedup_ordered(nums: &[i32]) -> Vec<i32> {
    let mut seen = HashSet::new();
    let mut result = Vec::new();
    for &num in nums {
        if seen.insert(num) {
            result.push(num);
        }
    }
    result
}

fn main() {
    let nums = vec![3, 1, 4, 1, 5, 9, 2, 6, 5, 3];
    println!("{:?}", dedup_ordered(&nums));
    // [3, 1, 4, 5, 9, 2, 6]
}

